var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"가도 가도 끝이 없네요...... 아지트엔 언제쯤 도착하나요?","JPN":"歩いても歩いても着きませんね……アジトにはいつ頃到着しますの？","ENG":"It feels we've been walking for hours. How far away are we from their hideout?","TWN":"不管怎麼走，就是沒有盡頭啊……還要多久才能到達他們的基地啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"조금만 참아. 얼마 안 남았어.","JPN":"もうちょっと頑張ってよ。あと少しだからさ。","ENG":"Keep walking, Regina. We're almost there.","TWN":"再忍耐一下，就要到了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그러니까 이쯤에서 잠깐 쉬면서 배 좀 채울까?","JPN":"じゃあ、そろそろちょっと休んで何か食べる？","ENG":"Or we can take a short break here and fill our tummies.","TWN":"那我們要不要在這裡稍微休息一下，填飽肚子如何？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지금 음식이 목구멍으로 넘어가요?","JPN":"この状況で食べ物がのどを通ると思います？","ENG":"How could you eat anything at a time like this?","TWN":"妳還可以吃得下東西？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"곧 싸워야 하잖아요. 전 긴장돼서 헛구역질이 나올 지경이라고요.","JPN":"戦いの時が迫っているのです。私は緊張して吐き気がしそうなくらいですわ。","ENG":"We're about to go into battle. I'm so nervous that I feel like I'm going to throw up.","TWN":"馬上就要戰鬥了吧，我緊張得都要吐出來了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"싸우기 전에는 배를 든든하게 채워야 하는 법. 노련한 용병에겐 상식이지.","JPN":"戦いの前だからこそ、しっかり食べとかないと。ベテラン傭兵の常識だよ。","ENG":"You can't fight with an empty belly. It's common sense among experienced mercenaries.","TWN":"打架前當然要把肚子填飽啊，這對經驗豐富的傭兵來說可是常識。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전 노련하지도 않고 용병도 아니에요. 전혀 공감 못하겠네요.","JPN":"私はベテランでも傭兵でもありませんから。全く共感できませんわ。","ENG":"I'm neither experienced nor a mercenary. I can hardly relate.","TWN":"我既沒有經驗豐富，也不是傭兵，完全無法體會呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에이, 레지나는 냉혈한이구나?","JPN":"ほんと、レジーナって冷たいよね。","ENG":"You just don't go with the flow, do you?","TWN":"哎呀，蕾佳娜可真冷漠啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"대학에서도 교수님들하고만 친하고 친구는 없지?","JPN":"大学でも教授とは仲良くても、友達はいないでしょ？","ENG":"You must be one of those types who's close with professors but doesn't have a single friend.","TWN":"妳在大學肯定只跟教授比較好，但完全沒有朋友吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"윽...... 그, 그걸 어떻게......?","JPN":"うっ……ど、どうしてそれを……？","ENG":"Oh... H-how did you know?","TWN":"唔……妳、妳怎麼知道……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"이번 기회에 다른 사람들이랑 친해지는 요령을 배워 둬. 싸울 때 친구 말고 누굴 믿겠어.","JPN":"このチャンスに、他の人と仲良くなる方法を学んだ方がいいよ。戦いで頼れるのは仲間だけだから。","ENG":"Use this opportunity to learn how to make some friends. Friends are the ones that watch your back in a fight.","TWN":"趁這個機會，來學學要怎麼和其他人打好關係的技巧吧？戰鬥的時候，不相信朋友還能相信誰啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"혹시나 해서 묻는데, 당신에게 친구란 뭐죠?","JPN":"念のために教えてほしいのですが、あなたにとって仲間とは何ですの？","ENG":"Just out of curiosity, what does 'friend' mean to you?","TWN":"以防萬一問一下，對妳來說朋友是什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"여차할 때 쓸 수 있는 고기방패.","JPN":"ピンチの時に便利な肉の盾。","ENG":"A meat shield that I can use in times of emergency.","TWN":"發生意外時的肉盾。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당장 출발하죠. 서두르면 날이 밝기 전에 저택으로 돌아갈 수 있을 거예요.","JPN":"すぐに出発しましょう。急げば夜が明ける前に邸宅に戻れるはずですわ。","ENG":"Let's just go. If we hurry, we'll be able to get back to the mansion before dawn.","TWN":"馬上出發吧。我們快一點的話，應該可以在天亮之前回到宅邸。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"나야 별로 상관없지만 에델은 많이 실망할 것 같은데?","JPN":"アタシは別に気にしないけど、エデルはきっとガッカリすると思うよ。","ENG":"I'm okay with it, but Edel will be very disappointed.","TWN":"我是沒什麼關係啦，但艾瑟兒好像會很失望的樣子喔？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델? 에델이 어쨌다고 그래요?","JPN":"エデル？　エデルがどうかしましたか？","ENG":"Edel? What about her?","TWN":"艾瑟兒？艾瑟兒怎麼了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"어머나, 숲 속에서 일행들과 단란하게 식사라니 멋진 생각이에요.","JPN":"あら、森の中でみんな仲良く食事なんて素敵なアイデアですね。","ENG":"Oh, a light meal with friends in the forest? That's a wonderful idea.","TWN":"哎呀，在森林裡大家聚在一起用餐什麼的，我們覺得很好呀。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"피크닉 세트를 챙겨 오길 잘했어요. 소풍 분위기가 물씬 나네요. 후훗.","JPN":"ピクニックセットを持ってきて正解でした。遠足みたいで楽しいです。ふふっ。","ENG":"It was really a good idea to bring the picnic package. It sure feels like picnic, doesn't it? Fu fu.","TWN":"幸好我們把野餐餐具也帶來了，很有郊遊的氣氛呢，呵呵。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"자, 돗자리도 준비해 두었답니다. 레지나 님도 옆에 앉으세요.","JPN":"レジャーシートも用意しておいたんですよ。レジーナ様も隣にどうぞ。","ENG":"Look, here's even a mat to sit on. Take a seat, Miss Regina.","TWN":"來，墊子我們也準備好了，蕾佳娜大人也請坐吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"보시라! 노련한 용병이란 의뢰주의 만족도도 놓치지 않는 법!","JPN":"見よ！　ベテラン傭兵たる者、クライアントの満足度を高めることも忘れないのだ！","ENG":"See? A skilled mercenary knows what the client wants!","TWN":"看吧！經驗豐富的傭兵連委託人的滿意度也不會忽略！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하아......","JPN":"ふう……","ENG":"*Sigh*","TWN":"哈啊……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"알겠어요, 알겠어. 조금만 쉬다가 가기로 하죠.","JPN":"分かりましたわ。少しだけ休んでから行きましょう。","ENG":"Okay, fine. We'll take a break.","TWN":"知道了，知道了。那就稍微休息一下再走吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"불꽃이 일렁거리는 게 정말 아름다워요.","JPN":"炎がゆれて美しいですね。","ENG":"The way the flame sways... It's beautiful.","TWN":"火焰晃動的樣子真美啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_CAMP_FIRE_LOOP"},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐, 분위기는 그리 나쁘지 않네요.","JPN":"まあ、雰囲気は意外と悪くないですわね。","ENG":"Well, I'd say this feels better than expected.","TWN":"算了，這氣氛也不壞呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"넌 모닥불에서 손 좀 치워줄래? 아까부터 냉기 때문에 불이 꺼지려고 하거든?","JPN":"アンタは焚火から手を離してくれる？　さっきから冷気のせいで火が消えそうなんだけど。","ENG":"Will you get your hands out of the fire, please? It's about to die out because of the freezing air you're emitting!","TWN":"妳的手能離火堆遠一點嗎？從剛才起火就因為冷氣差點熄滅耶？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이, 이런 걸로 야박하게 굴지 마세요!","JPN":"こ、こんなことで意地悪しないでくださいな！","ENG":"C-come on, you're just being mean!","TWN":"請、請不要用這種事來挖苦我！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아 참. 모닥불 구경하느라 깜빡 잊고 있었네요.","JPN":"そうそう、焚火を見ていたら忘れるところでした。","ENG":"Oh, dear. How could this be completely forgotten?","TWN":"啊，對了，忙著看火堆差點忘記了呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"고생하시는 두 분께 드리려고 제가 식사를 마련했답니다. 사양 말고 드세요.","JPN":"お疲れのご様子なので、お二人のためのお食事を\\n用意しておいたんです。さあ、召し上がってください。","ENG":"Here's some food prepared for you. You've been doing the hard work all along. Please help yourselves.","TWN":"兩位都辛苦了，我們為兩位準備了餐點。請享用吧，不要客氣。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"식사? 저택에서 샌드위치라도 싸 왔나요?","JPN":"食事？　邸宅からサンドイッチでも持ってきたのです？","ENG":"Food? Did you bring sandwiches from the mansion?","TWN":"餐點？是從宅邸帶來的三明治嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 그보다 훨씬 풍요로운 성찬이랍니다.","JPN":"いいえ。それよりもずっと豪華な聖餐ですよ。","ENG":"No, but it's something much nicer.","TWN":"不，是比那還要更豐盛的大餐喔。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"힉......?!","JPN":"ひッ……！","ENG":"Hic...","TWN":"咿……？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아이고야...... 또 저러네.","JPN":"あーあ……またやってる。","ENG":"Good gracious, she's doing it again.","TWN":"天啊……又來了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"치, 침식체잖아요! 지금 이걸 우리더러 먹으라고요?!","JPN":"し、侵食体ではありませんか！　これを食べろっていうんですか！？","ENG":"Th-this is a C.O.! Are you telling me to eat this?","TWN":"這、這不是侵蝕體嘛！妳現在是要我們吃這個？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"물론이죠. 얼마 전에 관리국도 침식체의 부산물로 만든 초콜릿을 나눠 준 적이 있답니다.","JPN":"もちろんです。先日、管理局も侵食体の副産物で作ったチョコレートを配布したんですよ。","ENG":"It's okay. Recently, the Administration also gave out chocolate made from Corrupted Object extracts.","TWN":"當然啦，管理局不久前也發送了以侵蝕體的副產物做成的巧克力。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그러니 침식체를 먹어도 된다는 건 검증된 사실이죠.","JPN":"ですから、侵食体は食べられるということは検証済みの事実なのです。","ENG":"It's a proven fact that you can eat Corrupted Objects.","TWN":"所以這證實了侵蝕體是可以吃的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"괜찮긴 뭐가 괜찮아요! 먹고 탈나기 전에 어서 저리 치워요!","JPN":"大丈夫なわけがないでしょう！　食べて体を壊す前に、片付けてください！","ENG":"Put that thing away! I'm going to get sick if I eat something like that!","TWN":"什麼沒關係！在吃出毛病前快給我扔掉！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그래도 배가 고픈걸요. 더 이상 참는 건 무리에요.","JPN":"それでもお腹が空いているでしょう？　これ以上我慢するのは無理ですよ。","ENG":"But we're hungry. We can't hold back anymore.","TWN":"但我們還是太餓了，已經沒辦法忍耐啦。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"후우...... 기다려 봐요.","JPN":"ふう……少し待っていてください。","ENG":"*Sigh* Wait up.","TWN":"喂……等一下。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이럴 줄 알고 제가 저택에서 식재료를 좀 챙겨 왔어요.","JPN":"こんなこともあろうかと、邸宅から食材を少し持って来ておきましたわ。","ENG":"I brought some ingredients from the mansion, just in case something like this happened.","TWN":"我就知道會發生這種事，所以從宅邸帶了些食材過來。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이걸로 간단한 식사라도 만들어 드릴게요.","JPN":"これで簡単な食事を用意します。","ENG":"I'll make you something to eat, although it won't be anything too fancy.","TWN":"這樣就能做些簡單的餐點了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러니까 그 끔찍한 건 빨리 가져다 버려요.","JPN":"ですから、その気持ちの悪い物体はどこかへ捨てて来てください。","ENG":"So please, throw that hideous thing away.","TWN":"所以快把這個可怕的東西拿開。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"으음...... 새로운 지식을 얻을 기회인데......","JPN":"うーん……新しい知識を得るチャンスなのですが……","ENG":"Hmm... But it's a good opportunity to absorb some new knowledge...","TWN":"嗯……這明明是個獲取新知識的機會……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아쉽지만 어쩔 수 없죠. 레지나 님이 손수 만든 요리라면 오늘은 포기할게요.","JPN":"残念ですが、仕方ありませんね。レジーナ様の手料理が食べられるなら、今日は諦めましょう。","ENG":"Oh, well. If it's for the food you make, we can give it up.","TWN":"雖然很可惜，但沒辦法呢。既然是蕾佳娜大人的親手料理，那我們今天就放棄吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"좋아요. 오래 걸리진 않을 테니까 잠시만 기다려요.","JPN":"はい。長くはかかりませんので、少しだけ待っていてください。","ENG":"Good. It won't take long.","TWN":"很好。不會很久的，稍微等一下吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"......샌드위치에서 살얼음이 씹히네.","JPN":"……サンドイッチが凍ってるんだけど。","ENG":"There are bits of ice in the sandwich.","TWN":"……吃三明治吃到碎冰了耶。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"여름 한정 메뉴인가?","JPN":"夏限定メニューなの？","ENG":"Is this a summer special menu?","TWN":"這是夏日限定菜單嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"조용히 하고 드세요. 저라고 잡는 것마다 얼어 버리는 게 좋을 리 없잖아요.","JPN":"文句は言わないでください。私だって掴むものが何でも凍ってしまうのは不本意なんですわ。","ENG":"Shut up and eat. Do you think I like freezing everything I touch?","TWN":"請安靜地吃。我也不喜歡，抓到什麼就凍結什麼。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델은 어때? 먹을 만해?","JPN":"エデルはどう？　食べられそう？","ENG":"What do you think, Edel? Is it any good?","TWN":"艾瑟兒覺得怎麼樣？還能吃吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"엉알 마이서여.","JPN":"ほへもおいひいでふ。","ENG":"*Munch* Ish wery elicious.","TWN":"哼得粉好ㄘ。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"먹고 말하세요. 사이비라고 해도 명색이 학회장이라면 품위를 지켜야죠.","JPN":"飲み込んでから話してください。インチキ集団でも\\n一応学会長を名乗っているのならば、品位は保った方がいいですわ。","ENG":"Swallow before you talk. Although to a group of pseudo researchers, you're a President. Behave yourself.","TWN":"請吃完了再說話。就算是邪教學會，但妳在名義上好歹也是個學會長，請保持用餐禮儀及品味。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"정말 맛있어요.","JPN":"とても美味しいです。","ENG":"It's very delicious.","TWN":"真的很好吃。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"새로운 지식이 없는 공허한 식사지만, 미각적으로는 굉장히 만족스럽네요.","JPN":"新しい知識のない虚しい食事ですが、味覚的にはとても満足していますよ。","ENG":"It's a rather empty meal without any new knowledge embedded in it, but taste-wise, it's very satisfying.","TWN":"雖然是沒有新知識而空虛的一餐，但味覺上令人非常滿意。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"기회가 되면 다음에 꼭 다시 만들어 주세요. 기다리고 있을게요.","JPN":"機会があったらまた作ってください。楽しみにしています。","ENG":"Make us that sandwich again when you have the chance, will you? We'll look forward to it.","TWN":"如果有機會的話，下次請務必再做一次，我們會好好期待的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"칭찬인지 욕인지 모르겠군요......","JPN":"褒めているのか、貶しているのかわかりませんわ……","ENG":"I’m not sure if that’s meant to be a compliment...","TWN":"真不知道這是稱讚還是壞話……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래도 다시 만들어 달라고 했으니까...... 마음에 들었단 뜻이겠죠?","JPN":"それでもまた作ってほしいということは……気に入ったという意味ですわね？","ENG":"But since you said you wanted to eat it again, I'll take it that you didn't hate it.","TWN":"不過既然會希望我下次再做……應該是喜歡的意思吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};